1	-------------------------------------------------------------------------------
2	-- Company    : SLAC National Accelerator Laboratory
3	-------------------------------------------------------------------------------
4	-- Description:
5	-- Block to connect multiple incoming AXI streams into a single encoded
6	-- outbound stream. The destination field is updated accordingly.
7	-------------------------------------------------------------------------------
8	-- This file is part of 'SLAC Firmware Standard Library'.
9	-- It is subject to the license terms in the LICENSE.txt file found in the
10	-- top-level directory of this distribution and at:
11	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
12	-- No part of 'SLAC Firmware Standard Library', including this file,
13	-- may be copied, modified, propagated, or distributed except according to
14	-- the terms contained in the LICENSE.txt file.
15	-------------------------------------------------------------------------------
16	
17	library ieee;
18	use ieee.std_logic_1164.all;
19	use ieee.std_logic_arith.all;
20	use ieee.std_logic_unsigned.all;
21	
22	library surf;
23	use surf.StdRtlPkg.all;
24	use surf.ArbiterPkg.all;
25	use surf.AxiStreamPkg.all;
26	
27	entity AxiStreamMux is
28	   generic (
29	      TPD_G                : time                    := 1 ns;
30	      RST_POLARITY_G       : sl                      := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
31	      RST_ASYNC_G          : boolean                 := false;
32	      PIPE_STAGES_G        : integer range 0 to 16   := 0;
33	      NUM_SLAVES_G         : integer range 1 to 256  := 4;
34	      -- In INDEXED mode, the output TDEST is set based on the selected slave index (default)
35	      -- In ROUTED mode, TDEST is set according to the TDEST_ROUTES_G table
36	      -- In PASSTHROUGH mode, TDEST is passed through from the slave untouched
37	      MODE_G               : string                  := "INDEXED";  -- Note: Planning to rename "MODE_G" to "TDEST_MODE_G" in a future MAJOR release of SURF
38	      -- In ROUTED mode, an array mapping how TDEST should be assigned for each slave port
39	      -- Each TDEST bit can be set to '0', '1' or '-' for passthrough from slave TDEST.
40	      TDEST_ROUTES_G       : Slv8Array               := (0 => "--------");
41	      -- In INDEXED mode, the output TID is set based on the selected slave index
42	      -- In ROUTED mode, TID is set according to the TID_ROUTES_G table
43	      -- In PASSTHROUGH mode, TID is passed through from the slave untouched (default)
44	      TID_MODE_G           : string                  := "PASSTHROUGH";
45	      -- In ROUTED mode, an array mapping how TID should be assigned for each slave port
46	      TID_ROUTES_G         : Slv8Array               := (0 => "--------");
47	      -- Assign a priority for each input stream index.
48	      -- Higher priority streams will be selected over those with lower priority of both are active.
49	      -- Format is (index => priority)
50	      -- Leave unchanged for equal priority round-robin
51	      PRIORITY_G           : IntegerArray            := (0 => 0);
52	      -- In INDEXED mode, assign slave index to TDEST at this bit offset
53	      TDEST_LOW_G          : integer range 0 to 7    := 0;
54	      -- Set to true if interleaving dests
55	      ILEAVE_EN_G          : boolean                 := false;
56	      -- Rearbitrate when tValid drops on selected channel, ignored when ILEAVE_EN_G=false
57	      ILEAVE_ON_NOTVALID_G : boolean                 := false;
58	      -- Max number of transactions between arbitrations, 0 = unlimited, ignored when ILEAVE_EN_G=false
59	      ILEAVE_REARB_G       : natural range 0 to 4095 := 0;
60	      -- One cycle gap in stream between during re-arbitration.
61	      -- Set true for better timing, false for higher throughput.
62	      REARB_DELAY_G        : boolean                 := true;
63	      -- Block selected slave txns arriving on same cycle as rearbitrate or disableSel from going through,
64	      -- creating 1 cycle gap. This might be needed logically but decreases throughput.
65	      FORCED_REARB_HOLD_G  : boolean                 := false);
66	
67	   port (
68	      -- Clock and reset
69	      axisClk      : in  sl;
70	      axisRst      : in  sl;
71	      -- Slaves
72	      disableSel   : in  slv(NUM_SLAVES_G-1 downto 0) := (others => '0');
73	      rearbitrate  : in  sl                           := '0';
74	      ileaveRearb  : in  slv(11 downto 0)             := toSlv(ILEAVE_REARB_G, 12);
75	      sAxisMasters : in  AxiStreamMasterArray(NUM_SLAVES_G-1 downto 0);
76	      sAxisSlaves  : out AxiStreamSlaveArray(NUM_SLAVES_G-1 downto 0);
77	
78	      -- Master
79	      mAxisMaster : out AxiStreamMasterType;
80	      mAxisSlave  : in  AxiStreamSlaveType);
81	end AxiStreamMux;
82	
83	architecture rtl of AxiStreamMux is
84	
85	   constant DEST_SIZE_C : integer := bitSize(NUM_SLAVES_G-1);
86	   constant ARB_BITS_C  : integer := 2**DEST_SIZE_C;
87	
88	   type RegType is record
89	      acks   : slv(ARB_BITS_C-1 downto 0);
90	      ackNum : slv(DEST_SIZE_C-1 downto 0);
91	      valid  : sl;
92	      arbCnt : slv(11 downto 0);
93	      slaves : AxiStreamSlaveArray(NUM_SLAVES_G-1 downto 0);
94	      master : AxiStreamMasterType;
95	   end record RegType;
96	
97	   constant REG_INIT_C : RegType := (
98	      acks   => (others => '0'),
99	      ackNum => toSlv(NUM_SLAVES_G-1, DEST_SIZE_C),
100	      valid  => '0',
101	      arbCnt => (others => '0'),
102	      slaves => (others => AXI_STREAM_SLAVE_INIT_C),
103	      master => AXI_STREAM_MASTER_INIT_C);
104	
105	   signal r   : RegType := REG_INIT_C;
106	   signal rin : RegType;
107	
108	   signal sAxisMastersTmp : AxiStreamMasterArray(NUM_SLAVES_G-1 downto 0);
109	   signal pipeAxisMaster  : AxiStreamMasterType;
110	   signal pipeAxisSlave   : AxiStreamSlaveType;
111	
112	   signal intDisableSel : slv(NUM_SLAVES_G-1 downto 0);
113	
114	begin
115	
116	   assert ((MODE_G = "PASSTHROUGH") or (MODE_G = "INDEXED") or (MODE_G = "ROUTED"))
117	      report "MODE_G must be either [PASSTHROUGH,INDEXED,ROUTED]"
118	      severity failure;
119	
120	   assert ((MODE_G = "INDEXED") and (7 - TDEST_LOW_G + 1 >= log2(NUM_SLAVES_G))) or (MODE_G /= "INDEXED")
121	      report "In INDEXED mode, TDest range 7 downto " & integer'image(TDEST_LOW_G) &
122	      " is too small for NUM_SLAVES_G=" & integer'image(NUM_SLAVES_G)
123	      severity failure;
124	
125	   assert ((MODE_G = "ROUTED") and (TDEST_ROUTES_G'length = NUM_SLAVES_G)) or (MODE_G /= "ROUTED")
126	      report "In ROUTED mode, length of TDEST_ROUTES_G: " & integer'image(TDEST_ROUTES_G'length) &
127	      " must equal NUM_SLAVES_G: " & integer'image(NUM_SLAVES_G)
128	      severity failure;
129	
130	   assert ((TID_MODE_G = "PASSTHROUGH") or (TID_MODE_G = "INDEXED") or (TID_MODE_G = "ROUTED"))
131	      report "TID_MODE_G must be either [PASSTHROUGH,INDEXED,ROUTED]"
132	      severity failure;
133	
134	   assert ((TID_MODE_G = "ROUTED") and (TID_ROUTES_G'length = NUM_SLAVES_G)) or (TID_MODE_G /= "ROUTED")
135	      report "In ROUTED mode, length of TID_ROUTES_G: " & integer'image(TID_ROUTES_G'length) &
136	      " must equal NUM_SLAVES_G: " & integer'image(NUM_SLAVES_G)
137	      severity failure;
138	
139	   -- Override TDESTS and TIDs according to the routing tables
140	   ROUTE_TABLE_REMAP : process (sAxisMasters) is
141	      variable tmp : AxiStreamMasterArray(NUM_SLAVES_G-1 downto 0);
142	   begin
143	      -- Latch the current value
144	      tmp := sAxisMasters;
145	
146	      -- Check for TDEST routing
147	      if MODE_G = "ROUTED" then
148	         for i in NUM_SLAVES_G-1 downto 0 loop
149	            for j in 7 downto 0 loop
150	               if (TDEST_ROUTES_G(i)(j) = '1') then
151	                  tmp(i).tDest(j) := '1';
152	               elsif(TDEST_ROUTES_G(i)(j) = '0') then
153	                  tmp(i).tDest(j) := '0';
154	               else
155	                  tmp(i).tDest(j) := sAxisMasters(i).tDest(j);
156	               end if;
157	            end loop;
158	         end loop;
159	      end if;
160	
161	      -- Check for TID routing
162	      if TID_MODE_G = "ROUTED" then
163	         for i in NUM_SLAVES_G-1 downto 0 loop
164	            for j in 7 downto 0 loop
165	               if (TID_ROUTES_G(i)(j) = '1') then
166	                  tmp(i).tId(j) := '1';
167	               elsif(TID_ROUTES_G(i)(j) = '0') then
168	                  tmp(i).tId(j) := '0';
169	               else
170	                  tmp(i).tId(j) := sAxisMasters(i).tId(j);
171	               end if;
172	            end loop;
173	         end loop;
174	      end if;
175	
176	      -- Outputs
177	      sAxisMastersTmp <= tmp;
178	
179	   end process;
180	
181	   -- When in INDEXED priority mode, tvalid on a given slave side index disables selection
182	   -- for all channels with higher index
183	   PRIORITY_CONTROL : process (disableSel, sAxisMasters) is
184	      variable tmp : slv(NUM_SLAVES_G-1 downto 0);
185	   begin
186	      tmp := disableSel;
187	
188	      for ch in NUM_SLAVES_G-1 downto 0 loop
189	         if (sAxisMasters(ch).tValid = '1') then
190	            if (ch < PRIORITY_G'length) then
191	               for sel in PRIORITY_G'range loop
192	                  if (PRIORITY_G(ch) > PRIORITY_G(sel)) then
193	                     tmp(sel) := '1';
194	                  end if;
195	               end loop;
196	            end if;
197	         end if;
198	      end loop;
199	
200	      intDisableSel <= tmp;
201	
202	   end process PRIORITY_CONTROL;
203	
204	   comb : process (axisRst, ileaveRearb, intDisableSel, pipeAxisSlave, r,
205	                   rearbitrate, sAxisMastersTmp) is
206	      variable v        : RegType;
207	      variable requests : slv(ARB_BITS_C-1 downto 0);
208	      variable selData  : AxiStreamMasterType;
209	   begin
210	      -- Latch the current value
211	      v := r;
212	
213	      -----------------------------------------------------------------------
214	
215	      -- AXI Stream Flow Control
216	      for i in 0 to (NUM_SLAVES_G-1) loop
217	         v.slaves(i).tReady := '0';
218	      end loop;
219	      if pipeAxisSlave.tReady = '1' then
220	         v.master.tValid := '0';
221	      end if;
222	
223	      -----------------------------------------------------------------------
224	
225	      -- Select source
226	      if NUM_SLAVES_G = 1 then
227	         selData := sAxisMastersTmp(0);
228	      else
229	         selData := sAxisMastersTmp(conv_integer(r.ackNum));
230	      end if;
231	
232	      -----------------------------------------------------------------------
233	
234	      -- In INDEXED mode, assign the slave index to TDEST at offset of TDEST_LOW_G
235	      if MODE_G = "INDEXED" then
236	         selData.tDest(7 downto TDEST_LOW_G)                         := (others => '0');
237	         selData.tDest(DEST_SIZE_C+TDEST_LOW_G-1 downto TDEST_LOW_G) := r.ackNum;
238	      end if;
239	
240	      -- In INDEXED mode, assign slave index to TID
241	      if (TID_MODE_G = "INDEXED") then
242	         selData.tId := resize(r.ackNum, 8);
243	      end if;
244	
245	      -----------------------------------------------------------------------
246	
247	      -- NOTE: MODE_G = "PASSTHROUGH and TID_MODE_G = "PASSTHROUGH" are degenerate cases.
248	      -- In the absence of "ROUTED" or "INDEXED", TDEST and TID are assigned
249	      -- directly from the slave input to the output master.
250	
251	      -----------------------------------------------------------------------
252	
253	      -- Format requests
254	      requests := (others => '0');
255	      for i in 0 to (NUM_SLAVES_G-1) loop
256	         requests(i) := sAxisMastersTmp(i).tValid and not intDisableSel(i);
257	      end loop;
258	
259	      if (r.valid = '1') then
260	         -- RE-arbitrate on gaps if configured to do so
261	         -- Also allow disableSel and rearbitrate to work at any time
262	         if (ILEAVE_EN_G) then
263	            if ((ILEAVE_ON_NOTVALID_G and selData.tValid = '0') or
264	                (rearbitrate = '1' or intDisableSel(conv_integer(r.ackNum)) = '1')) then
265	               v.valid := '0';
266	            end if;
267	         end if;
268	
269	         -- Check if able to move data
270	         -- Optionally hold  txns that arrive on same cycle as arbitrate or disableSel(r.ackNum)
271	         if ((v.master.tValid = '0') and (selData.tValid = '1') and
272	             (FORCED_REARB_HOLD_G = false or v.valid = '1')) then
273	
274	            -- Accept the data from slave
275	            v.slaves(conv_integer(r.ackNum)).tReady := '1';
276	
277	            -- Assign data to output
278	            v.master := selData;
279	
280	            -- Increment the txn count
281	            v.arbCnt := r.arbCnt + 1;
282	
283	            -- Check for tLast
284	            if selData.tLast = '1' then
285	               v.valid := '0';
286	
287	            -- Rearbitrate after ILEAVE_REARB_G txns
288	            elsif (ILEAVE_EN_G) and (ileaveRearb /= 0) and (r.arbCnt = ileaveRearb-1) then
289	               v.valid := '0';
290	            end if;
291	         end if;
292	      end if;
293	
294	      -- v.valid = 0 indicates re-arbitration, so reset arbCnt
295	      if (v.valid = '0') then
296	         v.arbCnt := (others => '0');
297	      end if;
298	
299	      -- Arbitrate between requesters
300	      if ((v.valid = '0' and REARB_DELAY_G = false) or r.valid = '0') then
301	         v.arbCnt := (others => '0');
302	         arbitrate(requests, r.ackNum, v.ackNum, v.valid, v.acks);
303	      end if;
304	
305	      -- Combinatorial outputs before the reset
306	      sAxisSlaves <= v.slaves;
307	
308	      -- Reset
309	      if (RST_ASYNC_G = false and axisRst = RST_POLARITY_G) then
310	         v := REG_INIT_C;
311	      end if;
312	
313	      -- Assign variable back to signal
314	      rin <= v;
315	
316	      -- Registered Outputs
317	      pipeAxisMaster <= r.master;
318	
319	   end process comb;
320	
321	   seq : process (axisClk, axisRst) is
322	   begin
323	      if (RST_ASYNC_G) and (axisRst = RST_POLARITY_G) then
324	         r <= REG_INIT_C after TPD_G;
325	      elsif rising_edge(axisClk) then
326	         r <= rin after TPD_G;
327	      end if;
328	   end process seq;
329	
330	   -- Optional output pipeline registers to ease timing
331	   AxiStreamPipeline_1 : entity surf.AxiStreamPipeline
332	      generic map (
333	         TPD_G          => TPD_G,
334	         RST_POLARITY_G => RST_POLARITY_G,
335	         RST_ASYNC_G    => RST_ASYNC_G,
336	         PIPE_STAGES_G  => PIPE_STAGES_G)
337	      port map (
338	         axisClk     => axisClk,
339	         axisRst     => axisRst,
340	         sAxisMaster => pipeAxisMaster,
341	         sAxisSlave  => pipeAxisSlave,
342	         mAxisMaster => mAxisMaster,
343	         mAxisSlave  => mAxisSlave);
344	
345	end rtl;
346

