25	
26	entity AxiStreamGearbox is
27	   generic (
28	      -- General Configurations
29	      TPD_G                : time     := 1 ns;
30	      RST_POLARITY_G       : sl       := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
31	      RST_ASYNC_G          : boolean  := false;
32	      READY_EN_G           : boolean  := true;
33	      PIPE_STAGES_G        : natural  := 0;
34	      SIDE_BAND_WIDTH_G    : positive := 1;    -- General purpose sideband
35	      FORCE_GEARBOX_IMPL_G : boolean  := false;  -- Set TRUE if you are using the gearbox to do the tKeep packing because not supported in surf.AxiStreamResize
36	      -- AXI Stream Port Configurations
37	      SLAVE_AXI_CONFIG_G   : AxiStreamConfigType;
38	      MASTER_AXI_CONFIG_G  : AxiStreamConfigType);
39	   port (
40	      -- Clock and reset
41	      axisClk     : in  sl;
42	      axisRst     : in  sl;
43	      -- Slave Port
44	      sAxisMaster : in  AxiStreamMasterType;
45	      sSideBand   : in  slv(SIDE_BAND_WIDTH_G-1 downto 0) := (others => '0');
46	      sAxisSlave  : out AxiStreamSlaveType;
47	      -- Master Port
48	      mAxisMaster : out AxiStreamMasterType;
49	      mSideBand   : out slv(SIDE_BAND_WIDTH_G-1 downto 0);
50	      mAxisSlave  : in  AxiStreamSlaveType);
51	end AxiStreamGearbox;
52	
53	architecture rtl of AxiStreamGearbox is
54	
55	   constant SLV_BYTES_C : positive := SLAVE_AXI_CONFIG_G.TDATA_BYTES_C;
56	   constant MST_BYTES_C : positive := MASTER_AXI_CONFIG_G.TDATA_BYTES_C;
57	
58	   constant SLV_USER_C : positive := ite(SLAVE_AXI_CONFIG_G.TUSER_BITS_C /= 0, SLAVE_AXI_CONFIG_G.TUSER_BITS_C, 1);
59	   constant MST_USER_C : positive := ite(MASTER_AXI_CONFIG_G.TUSER_BITS_C /= 0, MASTER_AXI_CONFIG_G.TUSER_BITS_C, 1);
60	
61	   constant WORD_MULTIPLE_C : boolean := (SLV_BYTES_C >= MST_BYTES_C and SLV_BYTES_C mod MST_BYTES_C = 0)
62	                                         or (MST_BYTES_C >= SLV_BYTES_C and MST_BYTES_C mod SLV_BYTES_C = 0);
63	
64	   constant TSTRB_EN_C : boolean := SLAVE_AXI_CONFIG_G.TSTRB_EN_C and MASTER_AXI_CONFIG_G.TSTRB_EN_C;
65	   constant TDEST_EN_C : boolean := (SLAVE_AXI_CONFIG_G.TDEST_BITS_C > 0) and (MASTER_AXI_CONFIG_G.TDEST_BITS_C > 0);
66	   constant TID_EN_C   : boolean := (SLAVE_AXI_CONFIG_G.TID_BITS_C > 0) and (MASTER_AXI_CONFIG_G.TID_BITS_C > 0);
67	   constant TUSER_EN_C : boolean := (SLAVE_AXI_CONFIG_G.TUSER_BITS_C > 0) and (MASTER_AXI_CONFIG_G.TUSER_BITS_C > 0)
68	                                    and (SLAVE_AXI_CONFIG_G.TUSER_MODE_C /= TUSER_NONE_C) and (MASTER_AXI_CONFIG_G.TUSER_MODE_C /= TUSER_NONE_C);
69	
70	   constant TDEST_BITS_C : natural := ite(TDEST_EN_C, minimum(SLAVE_AXI_CONFIG_G.TDEST_BITS_C, MASTER_AXI_CONFIG_G.TDEST_BITS_C), 1);
71	   constant TID_BITS_C   : natural := ite(TID_EN_C, minimum(SLAVE_AXI_CONFIG_G.TID_BITS_C, MASTER_AXI_CONFIG_G.TID_BITS_C), 1);
72	   constant TUSER_BITS_C : natural := ite(TUSER_EN_C, minimum(SLAVE_AXI_CONFIG_G.TUSER_BITS_C, MASTER_AXI_CONFIG_G.TUSER_BITS_C), 1);
73	
74	   constant MAX_C : positive := maximum(MST_BYTES_C, SLV_BYTES_C);
75	   constant MIN_C : positive := minimum(MST_BYTES_C, SLV_BYTES_C);
76	
77	   constant SHIFT_WIDTH_C : positive := wordCount(MAX_C, MIN_C) * MIN_C + MIN_C;
78	
79	   type RegType is record
80	      writeIndex : natural range 0 to SHIFT_WIDTH_C-1;
81	      tValid     : sl;
82	      tData      : slv(8*SHIFT_WIDTH_C-1 downto 0);
83	      tStrb      : slv(1*SHIFT_WIDTH_C-1 downto 0);
84	      tKeep      : slv(1*SHIFT_WIDTH_C-1 downto 0);
85	      tLast      : sl;
86	      tLastDly   : sl;
87	      tDest      : slv(TDEST_BITS_C-1 downto 0);
88	      tId        : slv(TID_BITS_C-1 downto 0);
89	      tUser      : slv(TUSER_BITS_C*SHIFT_WIDTH_C-1 downto 0);
90	      sideBand   : slv(SIDE_BAND_WIDTH_G-1 downto 0);
91	      sAxisSlave : AxiStreamSlaveType;
92	   end record RegType;
93	
94	   constant REG_INIT_C : RegType := (
95	      writeIndex => 0,
96	      tValid     => '0',
97	      tData      => (others => '0'),
98	      tStrb      => (others => '0'),
99	      tKeep      => (others => '0'),
100	      tLast      => '0',
101	      tLastDly   => '0',
102	      tDest      => (others => '0'),
103	      tId        => (others => '0'),
104	      tUser      => (others => '0'),
105	      sideBand   => (others => '0'),
106	      sAxisSlave => AXI_STREAM_SLAVE_INIT_C);
107	
108	   signal r   : RegType := REG_INIT_C;
109	   signal rin : RegType;
110	
111	   signal pipeAxisMaster : AxiStreamMasterType;
112	   signal pipeSideBand   : slv(SIDE_BAND_WIDTH_G-1 downto 0);
113	   signal pipeAxisSlave  : AxiStreamSlaveType;
114	
115	begin
116	
117	   -- When going from a large bus to a small bus, ready is necessary
118	   assert (SLV_BYTES_C <= MST_BYTES_C or READY_EN_G = true)
119	      report "READY_EN_G must be true if slave width is great than master" severity failure;
120	
121	   -- Can't use tkeep_fixed on master side when resizing or if not on slave side
122	   assert (not (MASTER_AXI_CONFIG_G.TKEEP_MODE_C = TKEEP_FIXED_C and
123	                SLAVE_AXI_CONFIG_G.TKEEP_MODE_C /= TKEEP_FIXED_C))
124	      report "AxiStreamGearbox: Can't have TKEEP_MODE = TKEEP_FIXED on master side if not on slave side"
125	      severity failure;
126	
127	   ---------------------------------------------------------
128	   -- Use AxiStreamResize if word multiple because less LUTs
129	   ---------------------------------------------------------
130	   GEN_RESIZE : if (WORD_MULTIPLE_C) and (not FORCE_GEARBOX_IMPL_G) generate
131	
132	      U_Resize : entity surf.AxiStreamResize
133	         generic map (
134	            -- General Configurations
135	            TPD_G               => TPD_G,
136	            RST_POLARITY_G      => RST_POLARITY_G,
137	            RST_ASYNC_G         => RST_ASYNC_G,
138	            READY_EN_G          => READY_EN_G,
139	            PIPE_STAGES_G       => PIPE_STAGES_G,
140	            SIDE_BAND_WIDTH_G   => SIDE_BAND_WIDTH_G,
141	            -- AXI Stream Port Configurations
142	            SLAVE_AXI_CONFIG_G  => SLAVE_AXI_CONFIG_G,
143	            MASTER_AXI_CONFIG_G => MASTER_AXI_CONFIG_G)
144	         port map (
145	            -- Clock and reset
146	            axisClk     => axisClk,
147	            axisRst     => axisRst,
148	            -- Slave Port
149	            sAxisMaster => sAxisMaster,
150	            sSideBand   => sSideBand,
151	            sAxisSlave  => sAxisSlave,
152	            -- Master Port
153	            mAxisMaster => mAxisMaster,
154	            mSideBand   => mSideBand,
155	            mAxisSlave  => mAxisSlave);
156	
157	   end generate;
158	
159	   GEN_GEARBOX : if (not WORD_MULTIPLE_C) or (FORCE_GEARBOX_IMPL_G) generate
160	
161	      comb : process (axisRst, pipeAxisSlave, r, sAxisMaster, sSideBand) is
162	
163	         variable tKeepTmp : slv(AXI_STREAM_MAX_TKEEP_WIDTH_C-1 downto 0);
164	         variable v        : RegType;
165	
166	      begin
167	         -- Latch the current value
168	         v := r;
169	
170	         -- Flow Control
171	         v.sAxisSlave.tReady := '0';
172	         if (pipeAxisSlave.tReady = '1') or (READY_EN_G = false) then
173	
174	            v.tValid := '0';
175	            v.tLast  := '0';
176	
177	            -- Check if previous word terminated the frame
178	            if (r.tLast = '1') then
179	
180	               -- Reset the sequence
181	               v.writeIndex := 0;
182	               v.tStrb      := (others => '0');
183	               v.tKeep      := (others => '0');
184	
185	            end if;
186	
187	         end if;
188	
189	         -- Only do anything if ready for data output
190	         if (v.tValid = '0') then
191	
192	            -- If current write index (assigned last cycle) is greater than output width, then we have to shift down before assigning an new input
193	            if (v.writeIndex >= MST_BYTES_C) then
194	
195	               -- Decrement the counter
196	               v.writeIndex := v.writeIndex - MST_BYTES_C;
197	
198	               -- Shift TDATA with zero padding
199	               v.tData := slvZero(8*MST_BYTES_C) & r.tData(8*SHIFT_WIDTH_C-1 downto 8*MST_BYTES_C);
200	
201	               -- Check if TSTRB enabled
202	               if(TSTRB_EN_C) then
203	                  -- Shift TSTRB with zero padding
204	                  v.tStrb := slvZero(1*MST_BYTES_C) & r.tStrb(1*SHIFT_WIDTH_C-1 downto 1*MST_BYTES_C);
205	               end if;
206	
207	               -- Shift TKEEP with zero padding
208	               v.tKeep := slvZero(1*MST_BYTES_C) & r.tKeep(1*SHIFT_WIDTH_C-1 downto 1*MST_BYTES_C);
209	
210	               -- Check if TUSER enabled
211	               if (TUSER_EN_C) then
212	                  -- Shift TUSER with zero padding
213	                  v.tUser := slvZero(TUSER_BITS_C*MST_BYTES_C) & r.tUser(TUSER_BITS_C*SHIFT_WIDTH_C-1 downto TUSER_BITS_C*MST_BYTES_C);
214	               end if;
215	
216	               -- If write index still greater than output width after shift, then we have a valid word to output
217	               if (v.writeIndex >= MST_BYTES_C) or (r.tLastDly = '1') then
218	
219	                  -- Set the flags
220	                  v.tValid         := '1';
221	                  if (v.writeIndex <= MST_BYTES_C) then
222	                     v.tLast    := r.tLastDly;
223	                     v.tLastDly := '0';
224	                  end if;
225	
226	               end if;
227	
228	            end if;
229	         end if;
230	
231	         -- Accept new data if ready to output and shift above did not create an output valid or terminate the frame
232	         if (sAxisMaster.tValid = '1') and (v.tValid = '0') and (v.tLast = '0') then
233	
234	            -- Accept the input word
235	            v.sAxisSlave.tReady := '1';
236	
237	            -- Assign incoming sideband
238	            v.sideBand := sSideBand;
239	
240	            -- ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~
241	            -- bit-by-bit assignment to appease ASIC synthesis flow tools
242	            -- ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~
243	            -- Assign incoming TDATA
244	            for i in (SLV_BYTES_C*8)-1 downto 0 loop
245	               v.tData((8*v.writeIndex)+i) := sAxisMaster.tData(i);
246	            end loop;
247	
248	            -- Check if TSTRB enabled
249	            if TSTRB_EN_C then
250	               for i in (SLV_BYTES_C)-1 downto 0 loop
251	                  v.tStrb(v.writeIndex+i) := sAxisMaster.tStrb(i);
252	               end loop;
253	            end if;
254	
255	            -- temporary variable
256	            tKeepTmp := genTKeep(conv_integer(sAxisMaster.tKeep(bitSize(SLV_BYTES_C)-1 downto 0)));
257	            -- Assign incoming TKEEP
258	            for i in (SLV_BYTES_C)-1 downto 0 loop
259	               if SLAVE_AXI_CONFIG_G.TKEEP_MODE_C = TKEEP_COUNT_C then
260	                  v.tKeep(v.writeIndex+i) := tKeepTmp(i);
261	               else
262	                  v.tKeep(v.writeIndex+i) := sAxisMaster.tKeep(i);
263	               end if;
264	            end loop;
265	            -- ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~
266	
267	            -- Check if TDEST enabled
268	            if(TDEST_EN_C) then
269	               v.tDest := sAxisMaster.tDest(TDEST_BITS_C-1 downto 0);
270	            end if;
271	
272	            -- Check if TID enabled
273	            if(TID_EN_C) then
274	               v.tId := sAxisMaster.tId(TID_BITS_C-1 downto 0);
275	            end if;
276	
277	            if (TUSER_EN_C) then
278	               for i in 0 to SLV_BYTES_C-1 loop
279	                  v.tUser(
280	                     (TUSER_BITS_C*v.writeIndex)+(i*TUSER_BITS_C)+(TUSER_BITS_C-1) downto
281	                     (TUSER_BITS_C*v.writeIndex)+(i*TUSER_BITS_C)) :=
282	                     sAxisMaster.tUser((i*SLV_USER_C)+(TUSER_BITS_C-1) downto (i*SLV_USER_C));
283	               end loop;
284	            end if;
285	
286	            -- Increment writeIndex
287	            v.writeIndex := v.writeIndex + getTKeep(resize(sAxisMaster.tKeep(1*SLV_BYTES_C-1 downto 0), AXI_STREAM_MAX_TKEEP_WIDTH_C), SLAVE_AXI_CONFIG_G);
288	
289	            -- Assert tValid
290	            if (v.writeIndex >= MST_BYTES_C) or (sAxisMaster.tLast = '1') then
291	
292	               -- Set the flags
293	               v.tValid   := '1';
294	               v.tLast    := '0';
295	               v.tLastDly := '0';
296	
297	               -- Check if spans frame termination two cycles
298	               if (v.writeIndex > MST_BYTES_C) then
299	                  v.tLastDly := sAxisMaster.tLast;
300	               else
301	                  v.tLast := sAxisMaster.tLast;
302	               end if;
303	
304	            end if;
305	
306	         end if;
307	
308	         -- Outputs
309	         sAxisSlave   <= v.sAxisSlave;
310	         pipeSideBand <= r.sideBand;
311	
312	         pipeAxisMaster.tValid <= r.tValid;
313	
314	         pipeAxisMaster.tData                           <= (others => '0');
315	         pipeAxisMaster.tData(8*MST_BYTES_C-1 downto 0) <= r.tData(8*MST_BYTES_C-1 downto 0);
316	
317	         pipeAxisMaster.tStrb <= (others => '0');
318	         if(TSTRB_EN_C) then
319	            pipeAxisMaster.tStrb(1*MST_BYTES_C-1 downto 0) <= r.tData(1*MST_BYTES_C-1 downto 0);
320	         else
321	            pipeAxisMaster.tStrb(1*MST_BYTES_C-1 downto 0) <= (others => '1');
322	         end if;
323	
324	         if (MASTER_AXI_CONFIG_G.TKEEP_MODE_C = TKEEP_COUNT_C) then
325	            pipeAxisMaster.tKeep <= toSlv(getTKeep(resize(r.tKeep(1*MST_BYTES_C-1 downto 0), AXI_STREAM_MAX_TKEEP_WIDTH_C), MASTER_AXI_CONFIG_G), AXI_STREAM_MAX_TKEEP_WIDTH_C);
326	         else
327	            pipeAxisMaster.tKeep                           <= (others => '0');
328	            pipeAxisMaster.tKeep(1*MST_BYTES_C-1 downto 0) <= r.tKeep(1*MST_BYTES_C-1 downto 0);
329	         end if;
330	
331	         pipeAxisMaster.tLast <= r.tLast;
332	
333	         pipeAxisMaster.tDest <= (others => '0');
334	         if(TDEST_EN_C) then
335	            pipeAxisMaster.tDest(TDEST_BITS_C-1 downto 0) <= r.tDest;
336	         end if;
337	
338	         pipeAxisMaster.tId <= (others => '0');
339	         if(TID_EN_C) then
340	            pipeAxisMaster.tId(TID_BITS_C-1 downto 0) <= r.tId;
341	         end if;
342	
343	         pipeAxisMaster.tUser <= (others => '0');
344	         if (TUSER_EN_C) then
345	            for i in 0 to MST_BYTES_C-1 loop
346	               pipeAxisMaster.tUser((i*MST_USER_C)+(TUSER_BITS_C-1) downto (i*MST_USER_C)) <=
347	                  r.tUser((i*TUSER_BITS_C)+(TUSER_BITS_C-1) downto (i*TUSER_BITS_C));
348	            end loop;
349	         end if;
350	
351	         -- Synchronous Reset
352	         if (RST_ASYNC_G = false and axisRst = RST_POLARITY_G) then
353	            v := REG_INIT_C;
354	         end if;
355	
356	         -- Register the variable for next clock cycle
357	         rin <= v;
358	
359	      end process comb;
360	
361	      seq : process (axisClk, axisRst) is
362	      begin
363	         if (RST_ASYNC_G) and (axisRst = RST_POLARITY_G) then
364	            r <= REG_INIT_C after TPD_G;
365	         elsif rising_edge(axisClk) then
366	            r <= rin after TPD_G;
367	         end if;
368	      end process seq;
369	
370	      ----------------------------------------------------
371	      -- Optional output pipeline registers to ease timing
372	      ----------------------------------------------------
373	      U_Pipeline : entity surf.AxiStreamPipeline
374	         generic map (
375	            TPD_G             => TPD_G,
376	            RST_POLARITY_G    => RST_POLARITY_G,
377	            RST_ASYNC_G       => RST_ASYNC_G,
378	            SIDE_BAND_WIDTH_G => SIDE_BAND_WIDTH_G,
379	            PIPE_STAGES_G     => PIPE_STAGES_G)
380	         port map (
381	            -- Clock and Reset
382	            axisClk     => axisClk,
383	            axisRst     => axisRst,
384	            -- Slave Port
385	            sAxisMaster => pipeAxisMaster,
386	            sSideBand   => pipeSideBand,
387	            sAxisSlave  => pipeAxisSlave,
388	            -- Master Port
389	            mAxisMaster => mAxisMaster,
390	            mSideBand   => mSideBand,
391	            mAxisSlave  => mAxisSlave);
392	
393	   end generate;
394	
395	end rtl;
396	
397

